#nullable enable // autogenerated

using MVZ2.GameContent.Armors;
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Enemies
{
    [EntityBehaviourDefinition(VanillaEnemyNames.NetherCourier)]
    public class NetherCourier : WitherSkeleton
    {
        public NetherCourier(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.SetAnimationBool("HasFlag", true);

            var speedBuff = entity.GetFirstBuff<RandomEnemySpeedBuff>();
            if (speedBuff != null)
            {
                RandomEnemySpeedBuff.SetSpeed(speedBuff, 2);
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelDamagePercent();

            if (entity.State == STATE_MELEE_ATTACK)
            {
                // 攻击时增加减伤buff  
                if (!entity.HasBuff<WarriorResistance>())
                {
                    var buff = entity.AddBuff<WarriorResistance>();
                    buff.SetProperty(WarriorResistance.PROP_Resistance_Level, 0.5f);
                }
                WitherAOE(entity, 2f, entity.GetFaction());
            }
            else
            {
                // 不攻击时去除减伤buff  
                if (entity.HasBuff<WarriorResistance>())
                {
                    entity.RemoveBuffs<WarriorResistance>();
                }
            }
        }
        public static void WitherAOE(Entity entity, float damage, int faction)
        {

            var range = 80;

            entity.Explode(
                entity.GetCenter(),
                range,
                faction,
                damage,
                new DamageEffectList(VanillaDamageEffects.DAMAGE_BOTH_ARMOR_AND_BODY, VanillaDamageEffects.MUTE, VanillaDamageEffects.WITHER, VanillaDamageEffects.WITHER)
            );


        }
        public const int STATE_MELEE_ATTACK = VanillaEnemyStates.MELEE_ATTACK;
    }
}
